module lb_reading #(
	parameter READ_DELAY=3
) (
	input clk,
	input reset,
	input lb_read,
	output lb_rvalid
);

reg [READ_DELAY-1:0] shift=0;
reg reading_r=0;
always @(posedge clk)
	if (reset) begin
		reading_r <= 0;
		shift <= 0;
	end else begin
		if (lb_read) reading_r <= 1;
		if (lb_rvalid) reading_r <= 0;
		shift <= lb_rvalid ? 0 : {shift[READ_DELAY-2:0], lb_read};
	end

assign lb_rvalid = shift[READ_DELAY-1] & ~reset;

endmodule

#!/usr/bin/env python

import fileinput

ptr = 0
data = []


def write_data():
    if len(data) != 0:
        print("@%08x" % (ptr >> 2))
        while len(data) % 4 != 0:
            data.append(0)
        for word_bytes in zip(*([iter(data)] * 4)):
            print("".join(["%02x" % b for b in reversed(word_bytes)]))


for line in fileinput.input():
    if line.startswith("@"):
        addr = int(line[1:], 16)
        if addr > ptr + 4:
            write_data()
            ptr = addr
            data = []
            while ptr % 4 != 0:
                data.append(0)
                ptr -= 1
        else:
            while ptr + len(data) < addr:
                data.append(0)
    else:
        data += [int(tok, 16) for tok in line.split()]

write_data()

// --------------------------------------------------------------
//  pico_pack.v
// --------------------------------------------------------------
// PicoRV32 CPU core wrapper. To get the packed interface

module pico_pack #(
    parameter [31:0] PROGADDR_RESET = 32'h 0000_0000,
    parameter [31:0] PROGADDR_IRQ = 32'h 0000_0010
) (
    input   clk,
    input   reset,
    output  trap,
    input   [31:0] irqFlags,        //trigger interrupt inputs
    output  [68:0] mem_packed_fwd,  //CPU > DEC
    input   [32:0] mem_packed_ret,  //CPU < DEC
    // lookahead mem intfc
    output        mem_la_read,
    output        mem_la_write,
    output [31:0] mem_la_addr,
    output [31:0] mem_la_wdata,
    output [ 3:0] mem_la_wstrb
);

// --------------------------------------------------------------
//  Unpack the MEM bus
// --------------------------------------------------------------
// What comes out of unpack
wire [31:0] mem_wdata;
wire [ 3:0] mem_wstrb;
wire        mem_valid;
wire [31:0] mem_addr;
wire [31:0] mem_rdata;
wire        mem_ready;
mpack mu (
    .mem_wdata ( mem_wdata  ),
    .mem_wstrb ( mem_wstrb  ),
    .mem_valid ( mem_valid  ),
    .mem_addr  ( mem_addr   ),
    .mem_ready ( mem_ready  ),
    .mem_rdata ( mem_rdata  ),

    .mem_packed_fwd( mem_packed_fwd ),
    .mem_packed_ret( mem_packed_ret )
);

// --------------------------------------------------------------
//  Fire interrupt 16-31 only on rising edges
// --------------------------------------------------------------
reg  [31:0] irqFlagsPrev;
wire [31:0] irqFlagsRising;
always @( posedge clk ) begin
    irqFlagsPrev <= irqFlags;
end
assign irqFlagsRising = irqFlags & ~irqFlagsPrev;

// --------------------------------------------------------------
//  Instantiate picorv32 CPU core
// --------------------------------------------------------------
wire trace_valid;
wire [35:0] trace_data;

picorv32 #(
    .ENABLE_COUNTERS      ( 1              ),
    .ENABLE_COUNTERS64    ( 1              ),
    .ENABLE_REGS_16_31    ( 1              ),
    .ENABLE_REGS_DUALPORT ( 1              ),
    .COMPRESSED_ISA       ( 1              ),// Enable support for compressed instr. set
    .ENABLE_IRQ           ( 1              ),// Enable interrupt controller
    .ENABLE_IRQ_QREGS     ( 1              ),
    .ENABLE_IRQ_TIMER     ( 1              ),
    .LATCHED_IRQ          ( 32'h FFFF_0007 ),// 1 = Interrupts are latched until served by ISR
    .PROGADDR_RESET       ( PROGADDR_RESET ),// Start into the bootloader at 0x00000000
    .PROGADDR_IRQ         ( PROGADDR_IRQ   ),// Interrupts jump into the main program at 0x0000010
    .CATCH_MISALIGN       ( 1              ),
    .BARREL_SHIFTER       ( 1              ),
    .ENABLE_MUL           ( 1              ),
    .ENABLE_FAST_MUL      ( 0              ),
    .ENABLE_DIV           ( 1              ),
    .TWO_CYCLE_COMPARE    ( 0              ),
    .TWO_CYCLE_ALU        ( 0              ),
    .STACKADDR            (`BLOCK_RAM_SIZE ),
`ifdef SIMULATE
    .ENABLE_TRACE    ( 1 )
`else
    .ENABLE_TRACE    ( 0 )
`endif
) picorv32_core (
    .clk         ( clk          ),
    .resetn      ( ~reset       ),        // cpu expects an active low reset
    .trap        ( trap         ),
    // IRQ Interface
    .irq         ( {irqFlagsRising[31:16],irqFlags[15:0]} ),    // 16 level trigger and 16 rising edge irq inputs, matches LATCHED_IRQ
    .eoi         (),
    // PicoRV32 Address Bus interface
    .mem_valid   ( mem_valid    ),
    .mem_ready   ( mem_ready    ),
    .mem_addr    ( mem_addr     ),
    .mem_wdata   ( mem_wdata    ),
    .mem_wstrb   ( mem_wstrb    ),
    .mem_rdata   ( mem_rdata    ),
    .mem_instr   (),
    // Look-Ahead Interface
    .mem_la_read ( mem_la_read  ),
    .mem_la_write( mem_la_write ),
    .mem_la_addr ( mem_la_addr  ),
    .mem_la_wdata( mem_la_wdata ),
    .mem_la_wstrb( mem_la_wstrb ),
    // Pico Co-Processor Interface (PCPI) (not used)
    .pcpi_valid   (),
    .pcpi_insn    (),
    .pcpi_rs1     (),
    .pcpi_rs2     (),
    .pcpi_wr      (1'b0),
    .pcpi_rd      (32'b0),
    .pcpi_wait    (1'b0),
    .pcpi_ready   (1'b0),
    // Trace Interface
    .trace_valid  (trace_valid),
    .trace_data   (trace_data)
);
`ifdef SIMULATE
    integer trace_file;
    initial begin
        trace_file = $fopen("pico.trace", "w");
        repeat (10) @(posedge clk);
        while (!trap) begin
            @(posedge clk);
            if (trace_valid)
                $fwrite(trace_file, "%x\n", trace_data);
        end
        $fclose(trace_file);
    end
`endif
endmodule

// --------------------------------------------------------------
//  mem_pack.v
//  Concatenate the whole MEM bus over 2 wires. To simplify
//  port definitions
// --------------------------------------------------------------

module mpack (
    // Unpacked wires
    input  [31:0] mem_wdata,    //CPU > MEM
    input  [ 3:0] mem_wstrb,    //CPU > MEM
    input  [31:0] mem_addr,     //CPU > MEM
    input         mem_valid,    //CPU > MEM
    output        mem_ready,    //CPU < MEM (TS)
    output [31:0] mem_rdata,    //CPU < MEM (TS)
    // Packed wires
    output [68:0] mem_packed_fwd,
    input  [32:0] mem_packed_ret
);
assign mem_packed_fwd = { mem_wdata, mem_wstrb, mem_addr, mem_valid };
assign mem_ready      =  mem_packed_ret[  32];
assign mem_rdata      =  mem_packed_ret[31:0];
endmodule

// --------------------------------------------------------------
//  mem_unpack.v
//  Restore the whole MEM bus from the 2 packed wires.
//  To simplify port definitions.
// --------------------------------------------------------------

module munpack (
    input clk,

    // Packed wires
    input  [68:0] mem_packed_fwd,
    output [32:0] mem_packed_ret,
    // Unpacked wires
    output [31:0] mem_wdata,    //CPU > MEM
    output [ 3:0] mem_wstrb,    //CPU > MEM
    output        mem_valid,    //CPU > MEM
    output [31:0] mem_addr,     //CPU > MEM
    input         mem_ready,    //CPU < MEM (TS)
    input  [31:0] mem_rdata     //CPU < MEM (TS)
);
assign mem_wdata      = mem_packed_fwd[68:37];
assign mem_wstrb      = mem_packed_fwd[36:33];
assign mem_addr       = mem_packed_fwd[32: 1];
assign mem_valid      = mem_packed_fwd[    0];

// only respond when asked. This looks redundant as peripherals should never
// set mem_rdata to anything else than 32'h0 unless they are asked for it
// wire [31:0] rdata = mem_ready ? mem_rdata : 0;
// assign mem_packed_ret = { mem_ready, rdata };

wire [32:0] temp = {mem_ready, mem_rdata};

// 0 cycles extra delay
// assign mem_packed_ret = temp;

// 1 cycle extra delay
reg[32:0] mem_packed_ret_ = 33'h0;
always @(posedge clk) mem_packed_ret_ <= temp;
assign mem_packed_ret = mem_packed_ret_;

endmodule

